module top_module(
    input clk,
    input parallel_load,
    input [3:0] in,
    output reg out
);reg [3:0] obf_shift_reg;

always @(posedge clk) begin
    if (parallel_load) begin
        obf_shift_reg <= in;
    end else begin
        obf_shift_reg <= {obf_shift_reg[2:0], obf_shift_reg[3]};
    end
end

assign out = obf_shift_reg[0];

endmodule
